const items = $input.all();

// Helper: يجيب أول binary value في الـ item
const getFirstBinary = (item) => {
  if (!item || !item.binary) return null;
  const keys = Object.keys(item.binary);
  return keys.length > 0 ? item.binary[keys[0]] : null;
};

const mainVideo = getFirstBinary(items[0]);
if (!mainVideo) throw new Error('Main video binary not found!');

const binaryData = {};
binaryData['video'] = mainVideo;

const playgroundVideo = getFirstBinary(items[1]);
if (playgroundVideo) binaryData['playground_video'] = playgroundVideo;

const audio = getFirstBinary(items[2]);
if (audio) binaryData['audio'] = audio;

const bgImage = getFirstBinary(items[3]);
if (bgImage) binaryData['background_image'] = bgImage;



return [{ json: {}, binary: binaryData }];

